/* ==========================================================================
PDF EXPORT — builds a print-ready two-column document off-screen and
rasterizes it with html2pdf.js
========================================================================== */
function renderPdfDocument(lang) {
    const d = CV_DATA[lang];
    // Base64 String Image for the PDF export.
    const photoSrc = "data:image/jpeg;base64,";    
    const contactHTML = d.contact.map(c => {
        // Pull the raw base64 string from our object map
        const base64Data = CONTACT_ICONS_BASE64[c.icon] || "";
        return `
        <li>
            <img src="${base64Data}" class="pdf-contact-icon" alt="${c.icon}" />
            <a href="${c.href}" target="_blank">${c.label}</a>
        </li>
    `;
    }).join('');
    
    const skillsHTML = d.skills.map(s =>
        `<div class="pdf-skill-block"><h4>${s.title}</h4><div class="pdf-skill-item"><span>${s.text}</span></div></div>`
    ).join('');
    
    const langHTML = d.languages.map(l =>
        `<li><b>${l.name}</b><span>${l.note}</span></li>`
    ).join('');
    
    const expHTML = d.experience.map((job, idx) => {
        const groupsHTML = job.groups.map(g => {
            const subHTML = g.sub ? `<div class="pdf-job-sub">${g.sub}</div>` : '';
            const bullets = g.bullets.map(b => `<li>${b}</li>`).join('');
            return `${subHTML}<ul>${bullets}</ul>`;
        }).join('');
        const skillsLineHTML = job.skillsLine
        ? `<div class="pdf-job-sub" style="margin-top:2mm;">${job.skillsLine}</div>`
        : '';
        
        // SI ES EL BLOQUE DE DRONE-HOPPER (ÍNDICE 2), LE METEMOS UNA CLASE ESPECIAL
        const extraClass = (idx === 2) ? 'pdf-top-page-buffer' : '';
        
        return `
    <div class="pdf-job ${extraClass}">
        <div class="pdf-job-head">
            <span class="pdf-job-title">${job.company}</span>
            <span class="pdf-job-dates">${job.dates}</span>
        </div>
        <div class="pdf-job-role">${job.role}</div>
        ${groupsHTML}
        ${skillsLineHTML}
    </div>`;
    }).join('');
    
    const eduHTML = d.education.map(e => {
        const linesHTML = e.lines.map(l => `<div class="pdf-edu-line">${l}</div>`).join('');
        return `
        <div class="pdf-edu-item">
            <div class="pdf-edu-head">
                <span class="pdf-edu-degree">${e.degree}</span>
                <span class="pdf-edu-dates">${e.dates}</span>
            </div>
            <div class="pdf-edu-org">${e.org}</div>
            ${linesHTML}
        </div>`;
    }).join('');
    
    return `
    <div class="pdf-doc" id="pdf-render-root">
        <div class="pdf-sidebar">
            ${photoSrc ? `<img class="pdf-photo" src="${photoSrc}" crossorigin="anonymous">` : ''}
            <h1 class="pdf-name">${d.name}</h1>
            <p class="pdf-role">${d.role}</p>
            <p class="pdf-status">${d.status}</p>
    
            <div class="pdf-block">
                <h3>${d.labels.contact}</h3>
                <ul class="pdf-contact-list">${contactHTML}</ul>
            </div>
    
            <div class="pdf-block">
                <h3>${d.labels.skills}</h3>
                ${skillsHTML}
            </div>
    
            <div class="pdf-block pdf-page-break">
                <h3>${d.labels.languages}</h3>
                <ul class="pdf-lang-list">${langHTML}</ul>
            </div>
        </div>
    
        <div class="pdf-main">
            <div class="pdf-main-section">
                <h2>${d.labels.summary}</h2>
                <p class="pdf-summary">${d.summary}</p>
            </div>
    
            <div class="pdf-main-section">
                <h2>${d.labels.experience}</h2>
                ${expHTML}
            </div>
    
            <div class="pdf-main-section">
                <h2>${d.labels.education}</h2>
                ${eduHTML}
            </div>
        </div>
    </div>`;
}

function exportCV(lang) {
    // normalize legacy calls (spanish/english) to short codes
    const key = (lang === 'spanish') ? 'es' : (lang === 'english') ? 'en' : lang;
    if (!CV_DATA[key]) {
        console.error('Unknown CV export language:', lang);
        return;
    }
    
    const dropdown = document.getElementById('dropdownContent');
    const trigger = dropdown ? dropdown.querySelector(`a[data-lang="${key}"]`) : null;
    if (trigger) trigger.classList.add('exporting');
    
    const holder = document.createElement('div');
    holder.className = 'pdf-doc-offscreen';
    holder.innerHTML = renderPdfDocument(key);
    document.body.appendChild(holder);
    
    const target = holder.querySelector('#pdf-render-root');
    const opt = {
        margin: 0,
        filename: `${CV_DATA[key].docTitle}.pdf`,
        image: { type: 'jpeg', quality: 0.98 },
        html2canvas: { scale: 4, useCORS: true, backgroundColor: '#ffffff', allowTaint: true },
        jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
        pagebreak: { mode: ['css', 'legacy'] }
    };
    
    html2pdf().set(opt).from(target).save().then(() => {
        document.body.removeChild(holder);
        if (trigger) trigger.classList.remove('exporting');
        if (dropdown) dropdown.classList.remove('show-dropdown');
    }).catch((err) => {
        console.error('PDF export failed:', err);
        document.body.removeChild(holder);
        if (trigger) trigger.classList.remove('exporting');
        alert('Something went wrong generating the PDF. Please try again.');
    });
}

// expose for inline onclick handlers in cv.html
window.exportCV = exportCV;